        className={`${btn} bg-white text-slate-600 ring-1 ring-slate-300 hover:bg-slate-50`}
        disabled={busy}
        onClick={() => run(() => readjudicateClaim(claimId))}
      >
        Re-adjudicate
      </button>
      <Err message={error} />
    </span>
